    public static List<EmailHistory> getConversation(NUIForm form,int nodeId){
        List<EmailHistory> result= new ArrayList<>();
        if(form==null) return result;

        //retrieve conversation from db
        BDBWorker worker=new BDBWorker(form.getApname());
        worker.setWhoami("EmailHistory.getConversation");
        try{
            SDBQuery q=new SDBQueryFull(worker);
            q.go(form.getRootDomainId());
            List<Integer> nodeIdList= new ArrayList<>();
            nodeIdList.add(nodeId);
            q.filter(nodeIdList);
            SDBNode node=q.next();

            //no such record
            if(node==null) return result;

            //go to its conversations
            q.go(DConst.EMAIL_TIMESTAMP);
            while((node=q.next())!=null){
                EmailHistory eh = new EmailHistory();
                SimpleDateFormat sdf=new SimpleDateFormat("yyyy/MM/dd HH:mm:ss.SSS");//[BugId:08817]
                try{eh.setTimestamp(sdf.parse(node.getValue()));}catch(Exception ex){
                    try {
                        SimpleDateFormat sdf2=new SimpleDateFormat("yyyy/MM/dd HH:mm:ss");
                        eh.setTimestamp(sdf2.parse(node.getValue()));}catch(Exception ex2){}
                }
                try{eh.setFrom(new InternetAddress(q.dip(DConst.EMAIL_FROM)));}catch(Exception ignored){}
                eh.setSubject(q.dip(DConst.EMAIL_SUBJECT));
                eh.setContent(q.dip(DConst.EMAIL_CONTENT));
                eh.setContentPlain(q.dip(DConst.EMAIL_CONTENT_PLAIN));

                String messageIdValue = q.dip(DConst.EMAIL_MESSAGEID);
                System.out.println(String.format("EMAIL_MESSAGEID: %s", messageIdValue));
                eh.setMessageId(messageIdValue);

                eh.setReferences(q.dip(DConst.EMAIL_REFERENCES));
                eh.setDownloadId(q.dip(DConst.EMAIL_DOWNLOAD_ID));
                List<SDBNode> nodeList=q.dipAllNodes(DConst.EMAIL_TO);
                for(SDBNode n:nodeList) eh.addTo(n.getValue());
                nodeList=q.dipAllNodes(DConst.EMAIL_CC);
                for(SDBNode n:nodeList) eh.addCC(n.getValue());
                nodeList=q.dipAllNodes(DConst.EMAIL_BCC);
                for(SDBNode n:nodeList) eh.addBCC(n.getValue());
                nodeList=q.dipAllNodes(DConst.EMAIL_ATTACH);
                for(SDBNode n:nodeList) eh.addAttach(n.getValue());

                String pathSheetIndex = q.dip(DConst.EMAIL_PATH_SHEETINDEX);
                if(pathSheetIndex != null && !pathSheetIndex.trim().isEmpty()) eh.setPathSheetIndex(pathSheetIndex);

                eh.setEmailToRead(q.dip(DConst.EMAIL_TO_READ_STATUS));
                eh.setEmailCcRead(q.dip(DConst.EMAIL_CC_READ_STATUS));

                result.add(eh);
            }
        }
        finally{
            worker.commit();
        }
        return result;
    }


