    private boolean isApnameNotExistThisServer(String apname) {
        boolean isNotOntThisServer = false;
        if(!Util.apnameExistsLocally(apname)){
            isNotOntThisServer = true;

            System.out.println(apname + " is not exist locally");
        }

        if (RedirectManager.getInstance().ifOnOtherServer(apname) ||
                (Const.AP_DEFAULT.equalsIgnoreCase(apname) && License.isProd()))
        {
            isNotOntThisServer = true;
        }

        if(isNotOntThisServer){
            System.out.println(apname+" is not on this server");

            return true;
        }
        return false;
    }

    public String getCcFiledOld(String cc){
        String ccEmail = "";
        String ccPersonal = "";
        List<InternetAddress> addressList = Encoder.parseMultiEmail(cc);
        for (InternetAddress addr : addressList) {
            if (ccEmail.length() > 0) ccEmail += ",";
            if (ccPersonal.length() > 0) ccPersonal += ",";
            if (addr.getAddress() != null && !addr.getAddress().isEmpty()) ccEmail += addr.getAddress();
            if (addr.getPersonal() != null && !addr.getPersonal().isEmpty()) ccPersonal += addr.getPersonal();
        }

        return ccEmail;
    }

    public String getCcFiled(String cc){
        String ccEmail = "";
        String ccPersonal = "";
        List<InternetAddress> addressList = Encoder.parseMultiEmail(cc, new SimpleEmailValidation());
        for (InternetAddress addr : addressList) {
            if (ccEmail.length() > 0) ccEmail += ",";
            if (ccPersonal.length() > 0) ccPersonal += ",";
            if (addr.getAddress() != null && !addr.getAddress().isEmpty()) ccEmail += addr.getAddress();
            if (addr.getPersonal() != null && !addr.getPersonal().isEmpty()) ccPersonal += addr.getPersonal();
        }

        return ccEmail;
    }


